/**
 * MarketCard — display card for a single HIP-4 prediction market.
 *
 * Shows: market label, underlying asset, Yes/No prices with color coding,
 * expiry countdown, and optional volume badge.
 *
 * Usage:
 *   <MarketCard
 *     market={market}
 *     yesMid={0.65}
 *     noMid={0.35}
 *     volume={1234}
 *     onClick={() => router.push(`/market/${market.yesCoin}`)}
 *   />
 */

"use client";

import type { Market } from "@purrdict/hip4";
import { CountdownTimer } from "./countdown-timer.js";
import { formatMidPrice, formatTargetPrice, formatPeriod, parseMid } from "../lib/format.js";

export interface MarketCardProps {
  market: Market;
  /**
   * Yes mid price (0–1). Pass mids[market.yesCoin] from useMarkets().
   * If not provided, the price is shown as "—".
   */
  yesMid?: number | string;
  /**
   * No mid price (0–1). Defaults to 1 − yesMid if not provided.
   */
  noMid?: number | string;
  /**
   * Optional 24h volume in USDH.
   */
  volume?: number;
  /** Called when the card is clicked */
  onClick?: () => void;
  /** Additional CSS classes */
  className?: string;
}

// Colour helpers — compatible with shadcn CSS variables.
function yesClass(px: number): string {
  if (px >= 0.6) return "text-green-500";
  if (px <= 0.4) return "text-red-500";
  return "text-foreground";
}

function noClass(px: number): string {
  if (px >= 0.6) return "text-green-500";
  if (px <= 0.4) return "text-red-500";
  return "text-foreground";
}

/**
 * A card showing a single prediction market.
 *
 * The card is a clickable surface when `onClick` is provided.
 * Styles use shadcn CSS variables so it inherits the host app's theme.
 */
export function MarketCard({
  market,
  yesMid: yesMidProp,
  noMid: noMidProp,
  volume,
  onClick,
  className = "",
}: MarketCardProps) {
  const yesPx = yesMidProp !== undefined ? parseMid(String(yesMidProp)) : 0;
  const noPx =
    noMidProp !== undefined
      ? parseMid(String(noMidProp))
      : yesPx > 0
        ? 1 - yesPx
        : 0;

  const hasPrice = yesPx > 0;

  const isClickable = !!onClick;

  return (
    <div
      role={isClickable ? "button" : undefined}
      tabIndex={isClickable ? 0 : undefined}
      onClick={onClick}
      onKeyDown={isClickable ? (e) => e.key === "Enter" && onClick?.() : undefined}
      className={[
        "rounded-lg border bg-card text-card-foreground shadow-sm p-4",
        "flex flex-col gap-3",
        isClickable
          ? "cursor-pointer hover:border-primary/50 hover:shadow-md transition-all"
          : "",
        className,
      ]
        .filter(Boolean)
        .join(" ")}
      aria-label={`${market.underlying} ${formatPeriod(market.period)} market`}
    >
      {/* Header: underlying + period */}
      <div className="flex items-start justify-between gap-2">
        <div>
          <p className="text-xs text-muted-foreground uppercase tracking-wide">
            {market.underlying}
          </p>
          <h3 className="font-semibold text-sm leading-tight">
            {market.underlying} Up or Down — {formatPeriod(market.period)}
          </h3>
          <p className="text-xs text-muted-foreground mt-0.5">
            Target: {formatTargetPrice(market.targetPrice)}
          </p>
        </div>

        {/* Volume badge */}
        {volume !== undefined && (
          <span className="shrink-0 text-xs bg-muted text-muted-foreground rounded px-1.5 py-0.5">
            Vol ${volume.toLocaleString()}
          </span>
        )}
      </div>

      {/* Yes / No prices */}
      <div className="grid grid-cols-2 gap-2">
        <div className="rounded bg-muted/50 p-2 text-center">
          <p className="text-xs text-muted-foreground mb-0.5">Yes</p>
          <p className={`font-bold text-base tabular-nums ${hasPrice ? yesClass(yesPx) : "text-muted-foreground"}`}>
            {hasPrice ? formatMidPrice(yesPx, "cents") : "—"}
          </p>
        </div>
        <div className="rounded bg-muted/50 p-2 text-center">
          <p className="text-xs text-muted-foreground mb-0.5">No</p>
          <p className={`font-bold text-base tabular-nums ${hasPrice ? noClass(noPx) : "text-muted-foreground"}`}>
            {hasPrice ? formatMidPrice(noPx, "cents") : "—"}
          </p>
        </div>
      </div>

      {/* Footer: countdown */}
      <div className="flex items-center justify-between text-xs text-muted-foreground">
        <span>Expires in</span>
        <CountdownTimer expiry={market.expiry} className="text-xs" />
      </div>
    </div>
  );
}

/**
 * CountdownTimer — live countdown to a prediction market expiry.
 *
 * Updates every second. Shows "Settled" when the expiry has passed.
 *
 * Usage:
 *   <CountdownTimer expiry={market.expiry} />
 *   <CountdownTimer expiry={market.expiry} className="text-sm text-muted-foreground" />
 */

"use client";

import { useState, useEffect } from "react";
import { formatCountdown } from "../lib/format.js";

export interface CountdownTimerProps {
  /** UTC expiry date */
  expiry: Date;
  /** Additional CSS classes */
  className?: string;
  /** Called when the timer reaches zero (once) */
  onExpire?: () => void;
}

/**
 * Live countdown timer that ticks every second.
 *
 * Renders the remaining time as a string (e.g. "2h 15m 30s").
 * Shows "Settled" after expiry.
 */
export function CountdownTimer({
  expiry,
  className = "",
  onExpire,
}: CountdownTimerProps) {
  const [display, setDisplay] = useState(() => formatCountdown(expiry));
  const [expired, setExpired] = useState(() => expiry.getTime() <= Date.now());

  useEffect(() => {
    // Recalculate when expiry changes.
    setDisplay(formatCountdown(expiry));
    setExpired(expiry.getTime() <= Date.now());
  }, [expiry]);

  useEffect(() => {
    if (expired) return;

    const interval = setInterval(() => {
      const formatted = formatCountdown(expiry);
      setDisplay(formatted);

      if (formatted === "Settled") {
        setExpired(true);
        onExpire?.();
        clearInterval(interval);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [expiry, expired, onExpire]);

  return (
    <span
      className={`font-mono tabular-nums ${expired ? "text-muted-foreground" : ""} ${className}`}
      aria-label={`Time until expiry: ${display}`}
    >
      {display}
    </span>
  );
}

/**
 * @purrdict/hip4-ui — formatting utilities.
 *
 * Price/time/number formatters shared across components.
 */

/**
 * Format a mid price for display.
 *
 * For prediction markets (values 0–1), shows cents-style formatting:
 *   0.55 → "55¢" or "0.55" depending on style
 *
 * @param px    Price as a number or string
 * @param style "cents" | "decimal" | "percent" — default "decimal"
 */
export function formatMidPrice(
  px: number | string,
  style: "cents" | "decimal" | "percent" = "decimal",
): string {
  const p = typeof px === "string" ? parseFloat(px) : px;
  if (isNaN(p)) return "—";

  if (style === "cents") {
    return `${(p * 100).toFixed(0)}¢`;
  }
  if (style === "percent") {
    return `${(p * 100).toFixed(1)}%`;
  }
  // Decimal — strip trailing zeros after 4 decimal places.
  return p.toFixed(4).replace(/\.?0+$/, "");
}

/**
 * Format a USDH amount for display.
 *
 * @param amount  Amount as a number
 * @param compact Show compact form for large numbers (e.g. "$1.2K")
 */
export function formatUsdh(amount: number, compact = false): string {
  if (isNaN(amount)) return "$0";
  if (compact && amount >= 1_000) {
    if (amount >= 1_000_000) return `$${(amount / 1_000_000).toFixed(1)}M`;
    if (amount >= 1_000) return `$${(amount / 1_000).toFixed(1)}K`;
  }
  return `$${amount.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

/**
 * Format a countdown from now to a future date.
 *
 * Returns:
 *   "2h 15m 30s" for > 2 hours
 *   "14m 30s"    for < 2 hours
 *   "45s"        for < 1 minute
 *   "Settled"    for past dates
 */
export function formatCountdown(expiry: Date): string {
  const msLeft = expiry.getTime() - Date.now();
  if (msLeft <= 0) return "Settled";

  const secs = Math.floor(msLeft / 1000);
  const mins = Math.floor(secs / 60);
  const hours = Math.floor(mins / 60);
  const days = Math.floor(hours / 24);

  if (days > 0) {
    const h = hours % 24;
    return `${days}d ${h}h`;
  }
  if (hours > 0) {
    const m = mins % 60;
    const s = secs % 60;
    return `${hours}h ${m}m ${s}s`;
  }
  if (mins > 0) {
    const s = secs % 60;
    return `${mins}m ${s}s`;
  }
  return `${secs}s`;
}

/**
 * Format a period string to human-readable label.
 *
 * "1m" → "1 Min"
 * "15m" → "15 Min"
 * "1h" → "1 Hour"
 * "1d" → "1 Day"
 */
export function formatPeriod(period: string): string {
  const match = period.match(/^(\d+)(m|h|d)$/);
  if (!match) return period;
  const n = parseInt(match[1]);
  const unit = match[2];
  const plural = n > 1;
  if (unit === "m") return `${n} Min`;
  if (unit === "h") return `${n} Hour${plural ? "s" : ""}`;
  if (unit === "d") return `${n} Day${plural ? "s" : ""}`;
  return period;
}

/**
 * Format a target price for display.
 *
 * 66200 → "66,200"
 * 66200.5 → "66,200.5"
 */
export function formatTargetPrice(price: number): string {
  return price.toLocaleString("en-US", {
    maximumFractionDigits: 2,
    minimumFractionDigits: 0,
  });
}

/**
 * Parse a mid price string to a number, returning 0 for invalid inputs.
 */
export function parseMid(s: string | undefined): number {
  if (!s) return 0;
  const n = parseFloat(s);
  return isNaN(n) ? 0 : n;
}

/**
 * Compute implied "No" price from a "Yes" price (since Yes + No = 1).
 */
export function noPrice(yesPx: number): number {
  return Math.max(0, Math.min(1, 1 - yesPx));
}
